36: 
37:     @Metadata(label = "producer",
38:               description = "To turn on logging when the mock receives an incoming message."
39:                             + " This will log only one time at INFO level for the incoming message. For more detailed logging, then set the"
40:                             + " logger to DEBUG level for the org.apache.camel.component.mock.MockEndpoint class.")
41:     private boolean log;
42:     @Metadata(label = "advanced", autowired = true,
43:               description = "To use a custom ExchangeFormatter to format the Exchange into a String suitable for logging.")
44:     private ExchangeFormatter exchangeFormatter;
45: 
46:     public MockComponent() {
47:     }
48: 
49:     public MockComponent(CamelContext context) {
50:         super(context);
51:     }
52: 
53:     @Override
54:     protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
55:         MockEndpoint endpoint = new MockEndpoint(uri, this);
56:         endpoint.setName(remaining);
57:         endpoint.setLog(log);
58: 
59:         Integer value = getAndRemoveParameter(parameters, "reportGroup", Integer.class);
60:         if (value != null) {
61:             Processor reporter = new ThroughputLogger(new CamelLogger("org.apache.camel.component.mock:" + remaining), value);
62:             endpoint.setReporter(reporter);
63:             endpoint.setReportGroup(value);
64:         }
65:         setProperties(endpoint, parameters);
66:         return endpoint;
67:     }
68: 
69:     @Override
70:     protected void doInit() throws Exception {
71:         if (exchangeFormatter == null) {
72:             DefaultExchangeFormatter def = new DefaultExchangeFormatter();
73:             def.setShowExchangeId(true);
74:             def.setShowExchangePattern(false);
75:             def.setSkipBodyLineSeparator(true);
76:             def.setShowBody(true);
77:             def.setShowBodyType(true);
78:             def.setStyle(DefaultExchangeFormatter.OutputStyle.Default);
79:             def.setMaxChars(10000);
80:             exchangeFormatter = def;
81:         }
82:     }
83: 
84:     public boolean isLog() {
85:         return log;
86:     }
87: 
88:     public void setLog(boolean log) {
89:         this.log = log;
90:     }
91: 
92:     public ExchangeFormatter getExchangeFormatter() {
93:         return exchangeFormatter;
94:     }
95: 
96:     public void setExchangeFormatter(ExchangeFormatter exchangeFormatter) {
97:         this.exchangeFormatter = exchangeFormatter;
98:     }
99: }
