62:     public Timer getTimer(TimerConsumer consumer) {
63:         String key = consumer.getEndpoint().getTimerName();
64:         if (!consumer.getEndpoint().isDaemon()) {
65:             key = "nonDaemon:" + key;
66:         }
67: 
68:         return timers.compute(key, (k, v) -> {
69:             if (v == null) {
70:                 // the timer name is also the thread name, so lets resolve a name to be used
71:                 String name = consumer.getEndpoint().getCamelContext().getExecutorServiceManager()
72:                         .resolveThreadName("timer://" + consumer.getEndpoint().getTimerName());
73:                 return new TimerHolder(new Timer(name, consumer.getEndpoint().isDaemon()));
74:             }
75:             v.refCount.incrementAndGet();
76:             return v;
77:         }).timer;
78:     }
79: 
80:     public void removeTimer(TimerConsumer consumer) {
81:         String key = consumer.getEndpoint().getTimerName();
82:         if (!consumer.getEndpoint().isDaemon()) {
83:             key = "nonDaemon:" + key;
84:         }
85:         timers.computeIfPresent(key, (k, v) -> {
86:             if (v.refCount.decrementAndGet() == 0) {
87:                 v.timer.cancel();
88:                 return null;
89:             }
90:             return v;
91:         });
92:     }
