package org.apache.camel.component.fix;

import java.util.Map;

import org.apache.camel.CamelContext;
import org.apache.camel.Endpoint;
import org.apache.camel.spi.Metadata;
import org.apache.camel.support.DefaultComponent;

/**
 * The FIX Component is for sending and receiving FIX protocol messages.
 */
@org.apache.camel.spi.annotations.Component("fix")
public class FixComponent extends DefaultComponent {

    @Metadata(label = "advanced",
              description = "To use a custom FIX engine")
    private FixEngine fixEngine;

    @Metadata(label = "advanced",
              description = "The default FIX configuration")
    private FixConfiguration configuration = new FixConfiguration();

    public FixComponent() {
    }

    public FixComponent(CamelContext context) {
        super(context);
    }

    @Override
    protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
        // The remaining part is the session ID
        FixEndpoint endpoint = new FixEndpoint(uri, this, remaining);

        // Copy the component-level configuration to the endpoint
        FixConfiguration copy = new FixConfiguration();
        if (configuration.getConfigFile() != null) {
            copy.setConfigFile(configuration.getConfigFile());
        }
        if (configuration.getSenderCompID() != null) {
            copy.setSenderCompID(configuration.getSenderCompID());
        }
        if (configuration.getTargetCompID() != null) {
            copy.setTargetCompID(configuration.getTargetCompID());
        }
        copy.setFixVersion(configuration.getFixVersion());
        copy.setHeartBeatInterval(configuration.getHeartBeatInterval());
        if (configuration.getSocketConnectHost() != null) {
            copy.setSocketConnectHost(configuration.getSocketConnectHost());
        }
        copy.setSocketConnectPort(configuration.getSocketConnectPort());

        endpoint.setConfiguration(copy);

        // Apply parameters to the endpoint
        setProperties(endpoint, parameters);

        return endpoint;
    }

    public FixEngine getFixEngine() {
        return fixEngine;
    }

    public void setFixEngine(FixEngine fixEngine) {
        this.fixEngine = fixEngine;
    }

    public FixConfiguration getConfiguration() {
        return configuration;
    }

    public void setConfiguration(FixConfiguration configuration) {
        this.configuration = configuration;
    }
}

