import org.apache.camel.support.DefaultConsumer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX Consumer receives FIX messages and feeds them into Camel routes
 */
public class FixConsumer extends DefaultConsumer implements FixMessageListener {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);

    private final FixEndpoint endpoint;

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
        this.endpoint = endpoint;
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        // Register this consumer as a message listener with the FIX engine
        FixComponent component = endpoint.getComponent();
        if (component != null && component.getFixEngine() != null) {
            component.getFixEngine().addMessageListener(endpoint.getSessionID(), this);
        }
        LOG.debug("FixConsumer started for session: {}", endpoint.getSessionID());
    }

    @Override
    protected void doStop() throws Exception {
        // Unregister this consumer from the FIX engine
        FixComponent component = endpoint.getComponent();
        if (component != null && component.getFixEngine() != null) {
            component.getFixEngine().removeMessageListener(endpoint.getSessionID(), this);
        }
        super.doStop();
        LOG.debug("FixConsumer stopped for session: {}", endpoint.getSessionID());
    }

    @Override
    public void onMessage(String message) {
        try {
            // Create an exchange for the incoming FIX message
            Exchange exchange = createExchange();
            exchange.getIn().setBody(message);
            exchange.getIn().setHeader(FixConstants.FIX_SESSION_ID, endpoint.getSessionID());

            // Process the exchange
            getProcessor().process(exchange);
        } catch (Exception e) {
            LOG.error("Error processing FIX message", e);
        }
    }

    protected Exchange createExchange() {
        return endpoint.createExchange();
    }
}

