    private final FixEndpoint endpoint;

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
        this.endpoint = endpoint;
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            // Get the FIX message from the exchange body
            String message = exchange.getIn().getBody(String.class);
            if (message == null) {
                exchange.setException(new IllegalArgumentException("FIX message body cannot be null"));
                callback.done(false);
                return false;
            }

            // Send the message via the FIX engine
            FixComponent component = endpoint.getComponent();
            if (component != null && component.getFixEngine() != null) {
                component.getFixEngine().sendMessage(endpoint.getSessionID(), message);
                LOG.debug("Sent FIX message on session: {}", endpoint.getSessionID());
            } else {
                exchange.setException(new IllegalStateException("FIX engine is not available"));
                callback.done(false);
                return false;
            }

            // Mark as successful
            callback.done(true);
            return true;
        } catch (Exception e) {
            LOG.error("Error sending FIX message", e);
            exchange.setException(e);
            callback.done(false);
            return false;
        }
    }
}

